UPDATE conteudos SET conteudo_texto = '<h2>Atualidades do Brasil</h2><p>Este resumo aborda os principais acontecimentos recentes do cenário nacional que são frequentemente cobrados em concursos da Petrobras.</p><h3>Economia Brasileira</h3><p>O Brasil possui uma economia diversificada, sendo destaque global em <strong>agronegócio, mineração e petróleo</strong>. A Petrobras é a maior empresa do país e uma das maiores petroleiras do mundo.</p><h4>Indicadores Econômicos</h4><ul><li><strong>PIB:</strong> O Produto Interno Bruto mede a riqueza produzida no país. O Brasil está entre as 10 maiores economias mundiais.</li><li><strong>Inflação:</strong> Medida pelo IPCA (Índice de Preços ao Consumidor Amplo), controlada pelo Banco Central através da taxa Selic.</li><li><strong>Taxa Selic:</strong> Taxa básica de juros da economia, definida pelo COPOM (Comitê de Política Monetária).</li></ul><h3>Política Nacional</h3><p>O Brasil é uma <strong>República Federativa Presidencialista</strong>, composta por 26 estados e o Distrito Federal.</p><h4>Três Poderes</h4><ul><li><strong>Executivo:</strong> Presidente da República, governadores e prefeitos.</li><li><strong>Legislativo:</strong> Congresso Nacional (Senado e Câmara dos Deputados).</li><li><strong>Judiciário:</strong> STF como órgão máximo, seguido pelos tribunais superiores.</li></ul><h3>Setor de Energia e Petróleo</h3><p>O <strong>Pré-sal</strong> brasileiro é uma das maiores descobertas de petróleo das últimas décadas, localizado na costa brasileira em águas ultraprofundas.</p><ul><li><strong>Campos principais:</strong> Lula, Búzios, Tupi, Sapinhoá.</li><li><strong>Produção:</strong> Brasil produz mais de 3 milhões de barris/dia.</li><li><strong>Autossuficiência:</strong> O país é autossuficiente em petróleo desde 2006.</li></ul><h3>Questões Ambientais</h3><p>Temas ambientais são muito cobrados em provas da Petrobras:</p><ul><li><strong>Amazônia:</strong> Desmatamento, queimadas e preservação.</li><li><strong>Transição energética:</strong> Investimentos em energias renováveis.</li><li><strong>Acordo de Paris:</strong> Compromissos brasileiros para redução de emissões.</li></ul><h3>Dicas para a Prova</h3><p>Fique atento aos acontecimentos dos últimos 2 anos. A Cesgranrio costuma cobrar:</p><ul><li>Reformas econômicas e políticas</li><li>Relações internacionais do Brasil</li><li>Avanços tecnológicos e científicos</li><li>Questões sociais relevantes</li></ul>' WHERE id = '7425f57c-a937-4978-bd37-f210dbf54bf5';

UPDATE conteudos SET conteudo_texto = '<h2>Atualidades Mundiais</h2><p>Panorama dos principais acontecimentos internacionais relevantes para concursos públicos.</p><h3>Geopolítica Global</h3><p>O cenário internacional é marcado por tensões e transformações constantes.</p><h4>Principais Conflitos e Tensões</h4><ul><li><strong>Guerra na Ucrânia:</strong> Conflito iniciado em 2022 entre Rússia e Ucrânia, com impactos globais em energia e alimentos.</li><li><strong>Tensões EUA-China:</strong> Disputa por hegemonia tecnológica e comercial.</li><li><strong>Oriente Médio:</strong> Conflitos históricos e questões energéticas.</li></ul><h3>Economia Global</h3><h4>Organismos Internacionais</h4><ul><li><strong>ONU:</strong> Organização das Nações Unidas - paz e segurança mundial.</li><li><strong>FMI:</strong> Fundo Monetário Internacional - estabilidade financeira.</li><li><strong>OMC:</strong> Organização Mundial do Comércio - regras de comércio.</li><li><strong>OPEP:</strong> Organização dos Países Exportadores de Petróleo - controle de produção.</li></ul><h4>Blocos Econômicos</h4><ul><li><strong>BRICS:</strong> Brasil, Rússia, Índia, China e África do Sul (expandido recentemente).</li><li><strong>União Europeia:</strong> 27 países com integração econômica e política.</li><li><strong>Mercosul:</strong> Bloco sul-americano com Brasil, Argentina, Uruguai e Paraguai.</li></ul><h3>Energia e Meio Ambiente</h3><p>Temas centrais no cenário atual:</p><h4>Transição Energética</h4><ul><li><strong>Energias renováveis:</strong> Solar, eólica e hidrogênio verde em expansão.</li><li><strong>Descarbonização:</strong> Metas globais para reduzir emissões de CO2.</li><li><strong>Petróleo:</strong> Ainda essencial, mas em processo de transição gradual.</li></ul><h4>Mudanças Climáticas</h4><ul><li><strong>COP (Conferência das Partes):</strong> Reuniões anuais sobre clima.</li><li><strong>Acordo de Paris:</strong> Meta de limitar aquecimento a 1,5°C.</li><li><strong>Eventos extremos:</strong> Aumento de secas, enchentes e ondas de calor.</li></ul><h3>Tecnologia e Inovação</h3><ul><li><strong>Inteligência Artificial:</strong> Revolução em diversos setores.</li><li><strong>5G:</strong> Nova geração de telecomunicações.</li><li><strong>Criptomoedas:</strong> Bitcoin e blockchain transformando finanças.</li></ul><h3>Saúde Global</h3><p>Pós-pandemia de COVID-19:</p><ul><li>Fortalecimento da OMS</li><li>Lições aprendidas sobre preparação para pandemias</li><li>Desenvolvimento acelerado de vacinas</li></ul>' WHERE id = '9878f823-9442-4af5-9524-cecefe69d2d4';

UPDATE conteudos SET conteudo_texto = '<h2>Meio Ambiente e Energia</h2><p>Conceitos fundamentais sobre sustentabilidade e matriz energética, temas muito cobrados em provas da Petrobras.</p><h3>Matriz Energética Brasileira</h3><p>O Brasil possui uma das matrizes energéticas mais limpas do mundo.</p><h4>Fontes de Energia</h4><ul><li><strong>Hidrelétrica (60%):</strong> Principal fonte, aproveitando rios como Paraná, São Francisco e Tocantins.</li><li><strong>Eólica (12%):</strong> Em forte expansão, principalmente no Nordeste.</li><li><strong>Solar (4%):</strong> Crescimento acelerado nos últimos anos.</li><li><strong>Termelétrica (15%):</strong> Gás natural e carvão como backup.</li><li><strong>Nuclear (2%):</strong> Usinas Angra 1, 2 e 3 (em construção).</li><li><strong>Biomassa (7%):</strong> Bagaço de cana e outros resíduos.</li></ul><h3>Petróleo e Gás Natural</h3><h4>Cadeia Produtiva</h4><ul><li><strong>Upstream:</strong> Exploração e produção (E&P).</li><li><strong>Midstream:</strong> Transporte e armazenamento.</li><li><strong>Downstream:</strong> Refino e distribuição.</li></ul><h4>Pré-sal Brasileiro</h4><p>Descoberto em 2006, é uma das maiores reservas do mundo:</p><ul><li>Localização: Costa sudeste, de Santa Catarina ao Espírito Santo.</li><li>Profundidade: 5.000 a 7.000 metros abaixo do nível do mar.</li><li>Desafios: Alta pressão, temperatura e distância da costa.</li></ul><h3>Sustentabilidade Empresarial</h3><h4>Conceitos ESG</h4><ul><li><strong>Environmental (Ambiental):</strong> Gestão de impactos ambientais.</li><li><strong>Social:</strong> Responsabilidade com comunidades e colaboradores.</li><li><strong>Governance (Governança):</strong> Transparência e ética nos negócios.</li></ul><h4>Práticas Sustentáveis</h4><ul><li>Redução de emissões de gases de efeito estufa</li><li>Gestão eficiente de recursos hídricos</li><li>Economia circular e reciclagem</li><li>Biodiversidade e compensação ambiental</li></ul><h3>Legislação Ambiental</h3><ul><li><strong>CONAMA:</strong> Conselho Nacional do Meio Ambiente.</li><li><strong>IBAMA:</strong> Instituto Brasileiro do Meio Ambiente.</li><li><strong>Licenciamento:</strong> LP (Prévia), LI (Instalação), LO (Operação).</li><li><strong>EIA/RIMA:</strong> Estudo e Relatório de Impacto Ambiental.</li></ul><h3>Transição Energética</h3><p>A Petrobras está investindo em:</p><ul><li><strong>Hidrogênio verde:</strong> Combustível do futuro.</li><li><strong>Captura de carbono:</strong> Tecnologia CCUS.</li><li><strong>Biocombustíveis:</strong> Diesel verde e bioquerosene.</li><li><strong>Energias renováveis:</strong> Eólica offshore e solar.</li></ul>' WHERE id = '3508e513-da0f-4f30-904f-e74dde36d577';

UPDATE conteudos SET conteudo_texto = '<h2>História do Brasil</h2><p>Resumo dos principais períodos históricos brasileiros cobrados em concursos.</p><h3>Brasil Colônia (1500-1822)</h3><h4>Descobrimento e Ocupação</h4><ul><li><strong>1500:</strong> Chegada de Pedro Álvares Cabral.</li><li><strong>Ciclo do Pau-Brasil:</strong> Primeira atividade econômica.</li><li><strong>Capitanias Hereditárias:</strong> Divisão territorial para colonização.</li><li><strong>Governo-Geral:</strong> Centralização administrativa (1548).</li></ul><h4>Ciclos Econômicos</h4><ul><li><strong>Cana-de-açúcar (XVI-XVII):</strong> Nordeste, trabalho escravo, engenhos.</li><li><strong>Mineração (XVIII):</strong> Ouro e diamantes em Minas Gerais.</li><li><strong>Café (XIX):</strong> Vale do Paraíba e depois Oeste Paulista.</li></ul><h3>Brasil Império (1822-1889)</h3><h4>Independência</h4><ul><li><strong>1822:</strong> Dom Pedro I proclama independência.</li><li><strong>1824:</strong> Primeira Constituição brasileira.</li></ul><h4>Períodos</h4><ul><li><strong>Primeiro Reinado:</strong> Dom Pedro I (1822-1831).</li><li><strong>Regências:</strong> Período de instabilidade (1831-1840).</li><li><strong>Segundo Reinado:</strong> Dom Pedro II (1840-1889).</li></ul><h4>Abolição da Escravidão</h4><ul><li><strong>1850:</strong> Lei Eusébio de Queiroz (fim do tráfico).</li><li><strong>1871:</strong> Lei do Ventre Livre.</li><li><strong>1885:</strong> Lei dos Sexagenários.</li><li><strong>1888:</strong> Lei Áurea (abolição total).</li></ul><h3>Brasil República</h3><h4>República Velha (1889-1930)</h4><ul><li>Política do café com leite (SP e MG).</li><li>Coronelismo e voto de cabresto.</li><li>Revoltas: Canudos, Contestado, Revolta da Vacina.</li></ul><h4>Era Vargas (1930-1945)</h4><ul><li><strong>Governo Provisório:</strong> 1930-1934.</li><li><strong>Constitucional:</strong> 1934-1937.</li><li><strong>Estado Novo:</strong> 1937-1945 (ditadura).</li><li>CLT (Consolidação das Leis do Trabalho).</li></ul><h4>República Democrática (1945-1964)</h4><ul><li>Governos eleitos democraticamente.</li><li>JK e o Plano de Metas (50 anos em 5).</li><li>Construção de Brasília.</li></ul><h4>Ditadura Militar (1964-1985)</h4><ul><li>AI-5: Ato Institucional mais repressivo.</li><li>Milagre econômico e crescimento.</li><li>Abertura lenta e gradual.</li></ul><h4>Nova República (1985-atual)</h4><ul><li>Redemocratização e Diretas Já.</li><li>Constituição de 1988 (Constituição Cidadã).</li><li>Plano Real (1994): estabilização econômica.</li></ul>' WHERE id = '46a9cae2-938a-44b9-b5d1-3e5d5e697bef';

UPDATE conteudos SET conteudo_texto = '<h2>Geografia do Brasil</h2><p>Aspectos físicos, econômicos e regionais do território brasileiro.</p><h3>Aspectos Físicos</h3><h4>Localização e Dimensões</h4><ul><li><strong>Área:</strong> 8,5 milhões km² (5º maior país do mundo).</li><li><strong>Localização:</strong> América do Sul, maior parte no hemisfério Sul.</li><li><strong>Fronteiras:</strong> 10 países (não faz fronteira com Chile e Equador).</li><li><strong>Litoral:</strong> 7.367 km de costa atlântica.</li></ul><h4>Relevo</h4><ul><li><strong>Planaltos:</strong> Predominantes (Planalto Brasileiro, Planalto das Guianas).</li><li><strong>Planícies:</strong> Amazônica, Pantanal, Costeira.</li><li><strong>Depressões:</strong> Amazônica, Sertaneja, Periférica.</li><li><strong>Pico mais alto:</strong> Pico da Neblina (2.993m) no Amazonas.</li></ul><h4>Clima</h4><ul><li><strong>Equatorial:</strong> Região Norte (quente e úmido).</li><li><strong>Tropical:</strong> Maior parte do Brasil.</li><li><strong>Semiárido:</strong> Interior do Nordeste.</li><li><strong>Subtropical:</strong> Região Sul (quatro estações definidas).</li></ul><h4>Hidrografia</h4><ul><li><strong>Bacia Amazônica:</strong> Maior do mundo em volume d''água.</li><li><strong>Bacia do Paraná:</strong> Maior potencial hidrelétrico.</li><li><strong>Bacia do São Francisco:</strong> Rio da integração nacional.</li><li><strong>Aquífero Guarani:</strong> Uma das maiores reservas de água doce subterrânea.</li></ul><h3>Biomas Brasileiros</h3><ul><li><strong>Amazônia:</strong> Maior floresta tropical, 49% do território.</li><li><strong>Cerrado:</strong> Savana brasileira, berço das águas.</li><li><strong>Mata Atlântica:</strong> Mais devastada, alta biodiversidade.</li><li><strong>Caatinga:</strong> Exclusivo do Brasil, adaptado à seca.</li><li><strong>Pampa:</strong> Campos sulinos, pecuária.</li><li><strong>Pantanal:</strong> Maior planície alagável do mundo.</li></ul><h3>Regiões Brasileiras</h3><h4>Norte</h4><p>Maior região em área, menor densidade demográfica. Economia: extrativismo e Zona Franca de Manaus.</p><h4>Nordeste</h4><p>Maior população entre as regiões. Contrastes: litoral úmido e sertão semiárido. Turismo e fruticultura irrigada.</p><h4>Centro-Oeste</h4><p>Fronteira agrícola do país. Agronegócio: soja, milho, algodão. Capital federal: Brasília.</p><h4>Sudeste</h4><p>Região mais industrializada e populosa. Maior PIB do país. Petróleo do pré-sal na costa.</p><h4>Sul</h4><p>Menor região em área. Alta qualidade de vida. Agricultura diversificada e indústria.</p><h3>Recursos Naturais e Petróleo</h3><p>O Brasil possui vastas reservas de:</p><ul><li><strong>Petróleo:</strong> Pré-sal na Bacia de Santos e Campos.</li><li><strong>Minérios:</strong> Ferro (Carajás), bauxita, manganês.</li><li><strong>Água doce:</strong> 12% das reservas mundiais.</li></ul>' WHERE id = 'b6934801-a167-46df-9eb6-dfd769097a1f';

UPDATE conteudos SET conteudo_texto = '<h2>Política Brasileira</h2><p>Sistema político e instituições do Brasil, conhecimentos essenciais para concursos.</p><h3>Forma de Estado e Governo</h3><ul><li><strong>República:</strong> O poder emana do povo, representantes eleitos.</li><li><strong>Federativa:</strong> União de estados autônomos.</li><li><strong>Presidencialista:</strong> Presidente é chefe de Estado e de Governo.</li><li><strong>Democrática:</strong> Baseada na soberania popular.</li></ul><h3>Os Três Poderes</h3><h4>Poder Executivo</h4><ul><li><strong>Federal:</strong> Presidente da República, Vice e Ministros.</li><li><strong>Estadual:</strong> Governadores e Secretários.</li><li><strong>Municipal:</strong> Prefeitos e Secretários.</li><li>Função: Administrar e executar políticas públicas.</li></ul><h4>Poder Legislativo</h4><ul><li><strong>Federal:</strong> Congresso Nacional (Senado + Câmara).</li><li><strong>Senado:</strong> 81 senadores (3 por estado), mandato de 8 anos.</li><li><strong>Câmara:</strong> 513 deputados federais, mandato de 4 anos.</li><li><strong>Estadual:</strong> Assembleias Legislativas.</li><li><strong>Municipal:</strong> Câmaras de Vereadores.</li><li>Função: Criar leis e fiscalizar o Executivo.</li></ul><h4>Poder Judiciário</h4><ul><li><strong>STF:</strong> Supremo Tribunal Federal (11 ministros).</li><li><strong>STJ:</strong> Superior Tribunal de Justiça.</li><li><strong>TSE:</strong> Tribunal Superior Eleitoral.</li><li><strong>TST:</strong> Tribunal Superior do Trabalho.</li><li><strong>STM:</strong> Superior Tribunal Militar.</li><li>Função: Julgar e interpretar as leis.</li></ul><h3>Constituição de 1988</h3><p>Conhecida como <strong>Constituição Cidadã</strong>:</p><ul><li>Promulgada em 5 de outubro de 1988.</li><li>Restabeleceu a democracia plena.</li><li>Ampliou direitos individuais e sociais.</li><li>Criou o SUS, definiu direitos trabalhistas.</li></ul><h4>Direitos Fundamentais</h4><ul><li><strong>Art. 5º:</strong> Direitos individuais (vida, liberdade, igualdade).</li><li><strong>Art. 6º:</strong> Direitos sociais (educação, saúde, trabalho).</li><li><strong>Art. 7º:</strong> Direitos dos trabalhadores.</li></ul><h3>Sistema Eleitoral</h3><ul><li><strong>Voto:</strong> Obrigatório (18-70 anos), facultativo (16-18 e +70).</li><li><strong>Eleições:</strong> A cada 4 anos (majoritárias e proporcionais).</li><li><strong>Sistema majoritário:</strong> Presidente, governadores, prefeitos, senadores.</li><li><strong>Sistema proporcional:</strong> Deputados e vereadores.</li></ul><h3>Órgãos de Controle</h3><ul><li><strong>TCU:</strong> Tribunal de Contas da União (fiscaliza gastos).</li><li><strong>CGU:</strong> Controladoria-Geral da União.</li><li><strong>MPU:</strong> Ministério Público da União.</li><li><strong>PF:</strong> Polícia Federal.</li></ul><h3>Petrobras e o Estado</h3><p>A Petrobras é uma <strong>sociedade de economia mista</strong>, com controle acionário da União. Está sujeita a:</p><ul><li>Lei das Estatais (Lei 13.303/2016).</li><li>Fiscalização do TCU.</li><li>Regras de governança corporativa.</li></ul>' WHERE id = 'b2d95b8b-c86e-49b2-a97a-fbc987024895';